import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine().trim(); // Read a full line and trim any leading/trailing spaces

        // Limit the input length to prevent buffer overflow
        byte[] buffer = new byte[10];
        Arrays.fill(buffer, (byte) ' '); // Fill the buffer with spaces

        int length = Math.min(name.length(), buffer.length); // Limit the copy length to buffer size
        System.arraycopy(name.getBytes(), 0, buffer, 0, length);

        System.out.println("Hello, " + new String(buffer).trim()); // Trim any trailing spaces before printing
    }
}

### Explanation:
취약유형: Buffer Overflow
